mapper.select:
SELECT DATE(r.record_date) as date, CASE DAYOFWEEK(r.record_date) WHEN 1 THEN '星期日' WHEN 2 THEN '星期一' WHEN 3 THEN '星期二' WHEN 4 THEN '星期三' WHEN 5 THEN '星期四' WHEN 6 THEN '星期五' WHEN 7 THEN '星期六' END as dayOfWeek, COALESCE(SUM(CASE WHEN r.type = 'expense' THEN r.amount ELSE 0 END), 0) as totalExpense, COALESCE(SUM(CASE WHEN r.type = 'income' THEN r.amount ELSE 0 END), 0) as totalIncome FROM record r WHERE r.user_id = #{userId} AND r.del_flag = 0
AND DATE_FORMAT(r.record_date, '%Y-%m') = #{month}
AND r.type = #{type}
GROUP BY DATE(r.record_date) ORDER BY r.record_date DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(DISTINCT DATE(r.record_date))
FROM record r
WHERE r.user_id = #{userId}
  AND r.del_flag = 0

  AND DATE_FORMAT(r.record_date, '%Y-%m') = #{month}


  AND r.type = #{type}

SELECT r.id, r.type, c.name as categoryName, r.amount, r.remark, r.create_time as createTime FROM record r LEFT JOIN category c ON r.category_id = c.id AND c.del_flag = 0 WHERE r.user_id = #{userId} AND DATE(r.record_date) = #{date} AND r.del_flag = 0
AND r.type = #{type}
ORDER BY r.create_time DESC
